angr_bug.c:
```c

#include <stdarg.h>
#include <stdio.h>

__attribute__((noinline))
int my_print_int(va_list args) {
  return printf("%d", va_arg(args, int));
}

__attribute__((noinline))
int my_print_string(va_list args) {
  return printf("%s", va_arg(args, const char *));
}

__attribute__((noinline))
int my_vprintf(const char *format, va_list args) {
  int i;
  int j = 0;
  for (i = 0; format[i]; ) {
    if ('%' == format[i]) {
      i += 1;
      if ('d' == format[i]) {
        j += my_print_int(args);
      } else if('s' == format[i]) {
        j += my_print_string(args);
      } else {
        putc('%', stdout);
        putc(format[i], stdout);
        j += 2;
      }
      i += 1;
    } else {
      putc(format[i], stdout);
      i += 1;
      j += 1;
    }
  }
  return j;
}

__attribute__((noinline))
int my_printf(const char *format, ...) {
  int ret = 0;
  va_list args;
  va_start(args, format);
  ret = my_vprintf(format, args);
  va_end(args);
  return ret;
}

int main(void) {
  my_printf("hello %d%s%d%s", 1, "a", 2, "b");
  return 0;
}

```

